VALUES
  ('real-estate-moex-01462', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列那幾項條件違反不動產估價技術規則中對應用計量模型分析法之要求？①須蒐集應用計量模型分析', '["計量模型分析採迴歸分析者，其調整後判定係數不得高於零 點七", "截距項以外其他各主要影響價格因素之係數估計值同時為零之顯著機率不得小於百分之五", "僅", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01463', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列對以進行開發為前提之宗地估價，何者正確？①得採土地開發分析法進行估價  ②得採收益法進行', '["並參酌比較法之評估結果決定其估價額", "並參酌成本法之評估結果決定其估價額", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01464', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '實際建築使用之容積率超過法定容積率之房地估價，應以那些部分之現況估價，並敘明法定容積對估值 之影響？', '["以所有實際建築使用部分估價", "以實際建築使用合法部分再扣除違章建築部分後估價", "以實際建築使用合法部分估價", "不論是否合法皆以法定容積率部分估價"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01465', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '續訂租約之租金估計，得採下列那些方式為之？①以續訂租約之租賃實例為標的，運用收益法估計之', '["勘估標的價格乘以租金收益率，以估計淨收益，再加計必要費用", "以勘估標的原契約租金之淨收益， 就其租金變動趨勢調整後，再加計必要費用", "分析企業經營之總收入，據以估計勘估標的在一定期間 內之淨收益，再加計必要費用", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01466', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '不動產租金估計，以估計勘估標的之實質租金為原則。此處實質租金指包括下列那些收益？①承租人每', '["押金運用收益", "保證金運用收益", "權利金運用收益", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01467', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '依土地開發分析法評估不動產價格時，如果開發後預期總銷售金額為 1億元，適當之利潤率為10%，開 發所需之直接成本為5,000萬元，開發所需之間接成本為3,000萬元，開發所需總成本之資本利息綜合利 率為4%，請問土地開發分析價格為何？（萬元以後四捨五入）', '["741萬元", "772萬元", "1,091萬元", "1,615萬元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01468', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '在使用比較法估價時，採用下列那些情況下之交易價格時，應先作適當之調整；該影響交易價格之情況', '["張先生因債務人無力償債而承接其抵押給張先生的廠房", "父子間之不動產買賣", "王先生因為移民急賣手上的不動產", "財政部國有財產署標售土地  ⑤臺中 市政府向教育部價購土地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01469', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '當比較標的收益價格為500萬元，勘估標的收益價格為800萬元，比較標的未來平均一年期間之客觀淨 收益為48萬元，勘估標的未來平均一年期間之客觀淨收益為40萬元，此時其收益資本化率為何？', '["5%", "6%", "8%", "9.6%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01470', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列有關土地建築開發之直接成本及間接成本之敘述，何者正確？①直接成本係指營造或施工費  ②規', '["直接成本包含規劃設計費", "間接成本不包含銷售費", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01471', 'real-estate', 'real-estate-moex-104-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '當債務保障比率為1.3，貸款常數為0.1，貸款以外的資金占不動產價格比率為 40%時，請問此時收益資 本化率為何？', '["3.1%", "5.2%", "6.5%", "7.8%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "3ca43697055c", "answer_pdf_sha1": "208afa3b65a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
